import style from "./index.module.scss"
import template from "./index.html"

export default class Home extends HTMLElement {
  static localName = "huanlin-home"
  constructor() {
    super();
  }
  
  connectedCallback() {
    this.classList.add("hydrated")
    const sheet = document.createElement("style")
    sheet.innerHTML = style
    this.innerHTML = template
    this.appendChild(sheet)
    this.render()
    const title = document.querySelector("#banner-center #title")
    title && (title.innerHTML = "Huanlin Huang")
    const donutData = [
      {
        "type": "React",
        "value": 5,
        "enabled": true
      },
      {
        "type": "Redux",
        "value": 3,
        "enabled": true
      },
      {
        "type": "JS",
        "value": 4,
        "enabled": true
      },
      {
        "type": "HTML",
        "value": 4,
        "enabled": true
      },
      {
        "type": "A11y",
        "value": 2,
        "enabled": true
      },
      {
        "type": "CSS",
        "value": 4,
        "enabled": true
      },
      {
        "type": "NodeJS",
        "value": 2,
        "enabled": true
      },
    ]
    const donut = this.querySelector('huanlin-donut')
    donut && donut.setAttribute("data", JSON.stringify(donutData))
  }

  render = () => {
   
  }
}
